INSERT OR IGNORE INTO connections (con_id,status,confidence,connection_type,filed_in,description,source_skill,opus_reviewed,session_applied,created_at,created_by_session,updated_at,updated_by_session) VALUES ('CON-0185','CONSUMED','HIGH',NULL,'bathrooms-and-wet-areas',NULL,NULL,1,NULL,'2026-05-08 21:00','session_2026-05-08-c1-migration','2026-05-08 21:00','session_2026-05-08-c1-migration');
INSERT OR IGNORE INTO connections (con_id,status,confidence,connection_type,filed_in,description,source_skill,opus_reviewed,session_applied,created_at,created_by_session,updated_at,updated_by_session) VALUES ('CON-0186','CONSUMED','HIGH',NULL,'sensory-environment',NULL,NULL,1,NULL,'2026-05-08 21:00','session_2026-05-08-c1-migration','2026-05-08 21:00','session_2026-05-08-c1-migration');
