-- Table evidence_population_match (22 rows)
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-001-SCHROEDER-1979','Schroeder & Steinfeld 1979 — The Estimated Cost of Accessible Buildings (HUD)','New construction accessibility cost premium (general)','US single-family + multi-family residential construction circa 1979',NULL,'PARTIAL','Study is 47 years old; US residential context. Construction methods and costs have evolved. The 0.5% figure is widely replicated by later studies (HUD Fair Housing 1988, RHFAC 2024) but each has its own population/era context.','2026-05-09 21:06','session_2026-05-09-verification','REF-VERIFIED-001');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-002-KOONTZ-2005','Koontz et al. 2005','Wheelchair users — general accessible ramp population','Manual wheelchair users start-up propulsion on indoor/outdoor surfaces',NULL,'PROXY','Study covered start-up propulsion on different surfaces, not specifically gradient validation. Provides background biomechanics but does not directly validate 1:20 threshold for SCI populations.','2026-05-09 23:11','session_2026-05-09-yang-verification','REF-VERIFIED-002');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-003-BJORK-1997','Björk et al. 1997','Hardware operating force threshold for UPL/PAIN populations including RA','Women with rheumatoid arthritis (N=20)',20,'PARTIAL','Population matches RA subset (most affected for grip-force door operation), but small sample (N=20), women only, single Swedish study. Cannot generalize to all UPL/PAIN populations. Provides one data point for grip force during RA flare but does not directly evaluate door-operation success at 22N.','2026-05-09 23:11','session_2026-05-09-chaffin-verification','REF-VERIFIED-004');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-004-IEC60118-4','IEC 60118-4 Ed 3.0','Hearing-aid users in built environments','Standard developed by IEC TC 29',NULL,'EXACT','Standards-track document directly addressing target population.','2026-05-09 23:37','session_2026-05-09-merge-rebase','REF-VERIFIED-005');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-005-ISO23599','ISO 23599:2019','Blind and vision-impaired pedestrians','ISO/TC 173 — accumulated 15+ years TWSI implementation evidence',NULL,'EXACT','Standards document directly addressing target population.','2026-05-09 23:37','session_2026-05-09-merge-rebase','REF-VERIFIED-006');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-006-FIA-2022','FIA 2022 + IFSM 2024','NDV/AUT users needing sensory-friendly alarm design','UK SEN schools (4 sites)',NULL,'PARTIAL','Strong domain match but UK-only, school-specific.','2026-05-09 23:37','session_2026-05-09-merge-rebase','REF-VERIFIED-007');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-007-AURACAST','Bluetooth SIG Auracast','Hearing-aid users in public venues','Standards-track + commercial deployment',NULL,'PARTIAL','NHS hearing aid users lag access.','2026-05-09 23:37','session_2026-05-09-merge-rebase','REF-VERIFIED-008');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-008-ERBER-1974','Erber 1974','DEAF/HoH adults relying on lipreading','Profoundly deaf children, group format',NULL,'PROXY','Children sample 50 years old. Findings about shadow effects likely generalize.','2026-05-09 23:37','session_2026-05-09-merge-rebase','REF-VERIFIED-009');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-009-FROHMAN-2013','Frohman et al. 2013','MS patients with thermal sensitivity','MS patients (review of multiple studies)',NULL,'PROXY','EXACT for thermal sensitivity in MS but PROXY for built-environment specification. Frohman 2013 reviews mechanism; built-environment translation requires assumption. Griggs 2019 (PMID 31414956) is exercise physiology, not built environment.','2026-05-09 23:37','session_2026-05-09-merge-rebase','REF-VERIFIED-011');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-010-CHRISTOGIANNI-2022','Christogianni et al. 2022','MS users with thermal sensitivity in built environments','MS patients (patient-centred study on thermal triggers and resilience)',NULL,'PARTIAL','Patient-centred perspective is appropriate for built-environment design context BUT study is qualitative/triggers focus, not quantitative threshold validation. Strong domain match, weaker metric match.','2026-05-10 05:07','session_2026-05-10-infrastructure','REF-VERIFIED-010');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-011-GRIGGS-2019','Griggs et al. 2019','SCI users in built environments','SCI individuals at REST in high ambient temperature (exercise physiology context)',NULL,'PROXY','PMID 31414956. CRITICAL CAVEAT: This is rest-state evaporative heat loss study, not built-environment temperature specification. Translation to building design is an assumption, not a direct validation.','2026-05-10 05:07','session_2026-05-10-infrastructure','REF-VERIFIED-012');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-012-LALUMIERE-2022','Lalumiere et al. 2022','Wheelchair users facing environmental barriers (ramps, kerbs, surfaces)','Systematic review covering 34 articles on wheelchair biomechanics across barrier types',34,'PARTIAL','Systematic review provides aggregate evidence across many populations and barrier types. Direct match for general wheelchair-user target population BUT specific gradient thresholds (e.g., 1:20 vs 1:14) require examining individual review-included studies.','2026-05-10 05:08','session_2026-05-10-infrastructure','REF-VERIFIED-003');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-SRU-FR-01','Cairn.info 2022 — Les espaces Snoezelen : quelle efficacité ?','NDV/AUT users of sensory rooms in built environment','Mixed populations (polyhandicap, intellectual disability, autism, elderly) using Snoezelen rooms — predominantly French/European institutional settings',NULL,'PARTIAL','Review covers Snoezelen broadly, not autism-specific. French practice is predominantly practitioner-mediated (accompagnateur controls stimuli) — diverges from BPC prior of USER control as primary. 41.7% of studies reported unfavorable cost-effectiveness. Snoezelen is a registered trademark creating commercial bias in evidence base.','2026-05-10 13:43:44','session_2026-05-10b-multilingual-sensory','REF-00700');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-SRU-ZH-01','PMC12673401 — SI-based intervention in autistic children, Chinese focus','NDV/AUT users of sensory rooms with user control as primary design variable','Chinese autistic children (6-12) receiving SI-based interventions in clinical/rehabilitation settings',NULL,'PROXY','Study addresses SI INTERVENTION effectiveness, not sensory ROOM DESIGN or user control. Chinese SI model is practitioner-directed (therapist controls stimuli progression), fundamentally different from BPC user-control-as-primary paradigm. Chinese practice frames sensory rooms as 感觉统合训练室 (SI training rooms) — clinical tool, not user-controlled environment. SI training in China explicitly positioned as supplementary to ABA, not standalone. Evidence on intervention effectiveness does NOT validate the user-control design claim.','2026-05-10 13:44:34','session_2026-05-10b-multilingual-sensory','REF-00701');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-SRU-KO-01','KCI 2022 — Korean SR of SI intervention for ASD children','NDV/AUT users of sensory rooms with user control as primary design variable','Korean ASD children receiving clinical SI therapy (OT-directed, private clinics/welfare centers/hospitals)',NULL,'PROXY','Study addresses SI INTERVENTION effectiveness in clinical settings, NOT sensory room design or user control. Korean SI is therapist-directed (일대일 치료 = 1:1 therapy). No Korean evidence found on user-controlled sensory rooms as built environment feature. Korean accessibility law (편의증진법) covers physical mobility only. Korean neurodiversity movement is active but not yet influencing built environment standards.','2026-05-10 13:45:35','session_2026-05-10b-multilingual-sensory','REF-00702');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-SRU-DA-01','McKee et al. 2007 — Snoezelen effect on disturbing behaviour in autism','NDV/AUT users of sensory rooms with user control as primary design variable','Persons with autism in Snoezelen rooms',NULL,'PARTIAL','ADVERSARIAL SOURCE. Study found NO evidence to support Snoezelen for autism. Examples of behavior WORSENING. Directly contradicts BPC synthesis that MSE use benefits autistic users. Does not specifically test user-control variable, but undermines the broader evidence base for sensory rooms serving this population.','2026-05-10 14:01:19','session_2026-05-10b-multilingual-sensory','REF-00703');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('MATCH-SRU-DA-02','Lotan & Gold 2009 — Meta-analysis Snoezelen for ID','NDV/AUT users of sensory rooms','Persons with intellectual disabilities (broader than autism)',NULL,'PROXY','Population is ID, not autism-specific. No significant effect found. Challenges the broader evidence base for Snoezelen/MSE effectiveness.','2026-05-10 14:01:19','session_2026-05-10b-multilingual-sensory','REF-00704');
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('EPM-S3-001','REF-00642','Autistic students in school built environments','Autistic students in schools (23 studies, mixed ages/settings)',NULL,'PARTIAL','Systematic review (not meta-analysis). Grey literature (not in PubMed). Mixed school settings including special and mainstream. "Strongest associations" claim for noise+visual is narrative synthesis, not quantified effect sizes.','2026-05-10T20:36:02Z','session_2026-05-10e-slug3-adversarial',NULL);
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('EPM-S3-002','REF-00710','Autistic students in school built environments','People with ASD in built environments (21 studies, predominantly school children)',NULL,'PARTIAL','Scoping review not specific to schools — includes residential/care. Three-factor model (sensory quality, intelligibility, predictability) is broader than noise+visual. No specific acoustic thresholds. Only 21/801 studies met criteria = thin evidence.','2026-05-10T20:36:02Z','session_2026-05-10e-slug3-adversarial',NULL);
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('EPM-S3-003','REF-00711','Autistic students in school built environments','People with ASD (literature review of design guidelines)',NULL,'PROXY','Review of design guidelines, not primary research. Confirms ASPECTSS as only framework. Acoustics is one of seven factors. Conference abstract (European Psychiatry), not full primary study.','2026-05-10T20:36:02Z','session_2026-05-10e-slug3-adversarial',NULL);
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('EPM-C4-001','REF-00551','Building occupants requiring circadian lighting support','Healthy adults (expert consensus based on multiple populations)',NULL,'PARTIAL','Brown 2022 is consensus for HEALTHY ADULTS. BPC applies to ALL populations including dementia, autism, etc. Dementia populations have different circadian disruption patterns. Translation to non-healthy-adult populations is an assumption. Kolberg 2022 (REF-00557) specifically studied dementia units.','2026-05-10T21:21:52Z','session_2026-05-10e-slug3-adversarial',NULL);
INSERT OR IGNORE INTO evidence_population_match (match_id,source_ref,target_population,study_population,sample_size,match_grade,mismatch_note,created_at,created_by_session,ref_id) VALUES ('EPM-C4-002','REF-00557','Dementia unit residents','Nursing home dementia unit residents (field measurement study)',NULL,'EXACT','Kolberg 2022 directly measured melanopic EDI in nursing home dementia units across seasons. Found insufficient m-EDI. EXACT match for dementia population in care setting.','2026-05-10T21:21:52Z','session_2026-05-10e-slug3-adversarial',NULL);

