INSERT OR IGNORE INTO evidence_sources (ref_id,authors,year,title,doi,doi_less_key,pmid,tier,evidence_type,jurisdiction,metadata_quality,verification_status,co1_provenance,co1_source_type,synthesis_attribution_required,notes,created_at,created_by_session,updated_at,updated_by_session,derivation_chain,prior_expectation,search_queries_used) VALUES ('REF-00700','Unknown (Cairn.info review)','2022','Les espaces Snoezelen : quelle efficacité ? Revue Médecine 2022(7):316','10.1684/med.2022.792',NULL,NULL,3,'narrative_review','FR',NULL,'VERIFIED',NULL,NULL,NULL,'French-language review on Snoezelen efficacy. Key finding: 41.7% of included studies reported unfavorable cost-effectiveness. Notes Snoezelen is a registered trademark (marque déposée). Found via multilingual remediation search.
[2026-05-11] Verified via CrossRef bibliographic search 2026-05-11 (CONFIRMED). Médecine 2022 journal (John Libbey Eurotext). Title and year match. Authors not in CrossRef metadata.','2026-05-10 13:43:44','session_2026-05-10b-multilingual-sensory','2026-05-11T04:19:23','session_2026-05-11g-citation-mining.md',NULL,'[BACKFILL — populated 2026-05-10 in session_2026-05-10c per audit Stage B.5. Per-source prior was NOT captured in real-time during the multilingual remediation. Meta-prior at session start: BPC synthesis claim ''user control is the primary design variable'' would be supported by Snoezelen-derived practice across languages. Anticipated cross-jurisdictional disagreement: practitioner-mediated framing in non-EN literature, possibly different therapeutic paradigms in East Asian SI traditions, and low-stimulus environment as alternative primary design strategy in Northern European housing literature. The per-language priors below are reconstructed from the EPM rows'' mismatch_note text and the handoff document''s per-language characterizations — they describe what was found, not what was expected, and should be read as such.]

Per-source post-hoc characterization: French Snoezelen practice is predominantly practitioner-mediated (accompagnateur controls stimuli) and has a registered trademark, both diverging from BPC''s user-control framing.','FR primary: ''Snoezelen autisme efficacité'' | FR adversarial: ''Snoezelen autisme critique limitation evidence cost-effectiveness''');
INSERT OR IGNORE INTO evidence_sources (ref_id,authors,year,title,doi,doi_less_key,pmid,tier,evidence_type,jurisdiction,metadata_quality,verification_status,co1_provenance,co1_source_type,synthesis_attribution_required,notes,created_at,created_by_session,updated_at,updated_by_session,derivation_chain,prior_expectation,search_queries_used) VALUES ('REF-00701','Unknown (PMC12673401)','2025','Effectiveness of sensory integration-based intervention in autistic children, focusing on Chinese children: a systematic review and meta-analysis','10.3389/fpsyt.2025.1623149',NULL,'PMC12673401',3,'systematic_review_meta_analysis','CN/INT',NULL,'VERIFIED',NULL,NULL,NULL,'SR+MA focusing on Chinese children with ASD receiving SI intervention. Key context: Chinese ASD prevalence 0.7% among school-aged (6-12), ~700,000 affected. Found via multilingual remediation search.
[2026-05-11] Verified via CrossRef bibliographic search 2026-05-11 (CONFIRMED). Frontiers in Psychiatry 2025 — Lyu et al. systematic review on SI for autistic Chinese children. PMC ID may differ from DB note (DB said PMC12673401) — DOI verified.','2026-05-10 13:44:34','session_2026-05-10b-multilingual-sensory','2026-05-11T04:19:23','session_2026-05-11g-citation-mining.md',NULL,'[BACKFILL — populated 2026-05-10 in session_2026-05-10c per audit Stage B.5. Per-source prior was NOT captured in real-time during the multilingual remediation. Meta-prior at session start: BPC synthesis claim ''user control is the primary design variable'' would be supported by Snoezelen-derived practice across languages. Anticipated cross-jurisdictional disagreement: practitioner-mediated framing in non-EN literature, possibly different therapeutic paradigms in East Asian SI traditions, and low-stimulus environment as alternative primary design strategy in Northern European housing literature. The per-language priors below are reconstructed from the EPM rows'' mismatch_note text and the handoff document''s per-language characterizations — they describe what was found, not what was expected, and should be read as such.]

