INSERT OR IGNORE INTO evidence_sources (ref_id,authors,year,title,doi,doi_less_key,pmid,tier,evidence_type,jurisdiction,metadata_quality,verification_status,co1_provenance,co1_source_type,synthesis_attribution_required,notes,created_at,created_by_session,updated_at,updated_by_session,derivation_chain,prior_expectation,search_queries_used) VALUES ('REF-00702','Korean OT researchers (KCI/Korea Science)','2022','Systematic review of SI intervention methods for ASD children in Korea (국내 자폐스펙트럼장애 아동 감각통합 중재방법)',NULL,NULL,NULL,3,'systematic_review','KR',NULL,'PROBABILISTIC',NULL,NULL,NULL,'Korean SR: 10 studies, all showed positive SI effects on ASD children. BUT: predominantly single-subject designs (not RCTs); calls for higher quality evidence. Measures used: Sensory Profile + COPM. Covers clinical intervention, NOT room design or user control.
