INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-005','EC','P2','CLOSED-SYNC','economics-auditor','E-01','EA-C3 E-01: Lifecycle framing absent on cost-significant item. No evidence that total cost over time (avoided retrofit penalty, avoided exclusion costs) justifies capital investment. Economics-researcher to supply lifecycle offset evidence for lift provision. [economics BPC has relevant data]','2026-05-08 18:00','session_2026-05-08-co0009-phase3','2026-05-08 18:00','session_2026-05-08-bpc-crossref-deep',NULL,NULL,NULL,NULL);
