INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-007','AUDT','P3','CLOSED-FIXED','economics-auditor','E-01','EA-C6/FR-4 E-01: ''20x cost multiplier versus design-stage provision'' — specific numerical claim with no citation. ''Well documented'' is an assertion, not a source. ISW to either cite source(s) for the 20x figure or reframe as qualitative (''significant cost multiplier''). [FIXED: 20x reframed to qualitative in failures_json]','2026-05-08 18:00','session_2026-05-08-co0009-phase3','2026-05-09 05:10','session_2026-05-09-authoring',NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-008','RP','P3','OPEN','connection-discovery','I-01','connection-discovery spec I-01: ≤22 N force threshold cites ISO 21542 and CSA B651 (code standards) but no primary research for the numeric value. Cross-reference with research on grip force ranges for UPL populations to confirm or adjust threshold. [Reclassified CR→RP: primary research gap, not cross-reference] [RESEARCH 2026-05-09: Multiple international standards converge on similar force thresholds (ADA 5 lbs/22 N, BS 8300, DIN 18040, AS 1428.1) but all are standards-consensus values. No primary clinical research found on grip force threshold derivation for disability populations. Evidence base: INTERNATIONAL CONSENSUS (Tier 5-6) — adequate for standards-based specification but FDR stands for primary research on UPL-specific force capacity.] [VERIFICATION 2026-05-09 23:11: Chaffin 2006 NOT VERIFIED. Björk 1997 (PMID 9021280) IS real RA grip force study. The specific 22N citation chain remains untraced to primary data.]','2026-05-08 18:31','session_2026-05-08-co0009-phase4-pipeline-test','2026-05-09 23:11','session_2026-05-09-chaffin-verification','Recommendation would change if: (a) Björk 1997 or successor RA grip force studies show 22N exceeds capacity for >10% of RA flare population (N>30); OR (b) ISO 21542 working group documentation cannot defend 22N derivation; OR (c) post-occupancy data shows hardware-related access failures correlate with 22N threshold.','40-55%','Drops to 25-35% if specific Chaffin et al. 2006 citation cannot be located (search shows it likely does not exist as I described it). Rises to 65-80% if Björk et al. 1997 (PMID 9021280) and successor studies are consulted directly to assess RA grip force vs door operation thresholds.','PARTIAL VERIFICATION: Real RA grip force literature exists — Björk et al. 1997 "Assessments of disability in women with rheumatoid arthritis in relation to grip force and pain" (PMID 9021280, N=20 women with RA). Specific Chaffin et al. 2006 citation I used in protocol v1 example: NOT VERIFIED — likely fabricated or misattributed. Industry literature (Tru Grip, RheumatoidArthritis.net) confirms door knobs are difficult during RA flare but provides no specific N or threshold data.');
INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-009','MX','P3','CLOSED-FIXED','content-gap-analyzer','I-01','coverage I-01: MOB and PAIN listed in Applicable Groups but spec provides no population-specific rationale. UPL Biomechanical FOR is well-articulated; MOB (wheelchair hardware access) and PAIN (grip pain reduction) rationales absent. ISW to add brief per-population rationale. [FIXED: population-specific rationales added to pop_reasons_json]','2026-05-08 18:32','session_2026-05-08-co0009-phase4-pipeline-test','2026-05-08 18:32','session_2026-05-08-mech-fix',NULL,NULL,NULL,NULL);
