INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-011','AUDT','P3','CLOSED-SYNC','evidence-auditor','I-01','UNSTATED I-01: ≤22 N force threshold cites ISO 21542:2021 and CSA B651:2023 (code standards, Tier 4-5) but no evidence stratum stated. ISW to add stratum annotation: EMERGING (international code standard consensus, no clinical intervention research on the specific value). [spec-db has tier: Co-1/Tier 3]','2026-05-08 18:32','session_2026-05-08-co0009-phase4-pipeline-test','2026-05-08 18:32','session_2026-05-08-bpc-crossref-deep',NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-012','RP','P2','OPEN','functional-deficit-auditor','I-01','UPL+DEM compound: no indexed evidence for cognitive-physical compound hardware selection. FDR trigger: d440 + UPL+DEM compound → hardware operability. (CON-0251 cleanup — connection not in SQLite DB, likely from archived MD register; gap logged as corrective action per CO-0009 §6.) [RESEARCH 2026-05-09: No indexed evidence for cognitive-physical compound hardware selection found. UPL+DEM compound is a novel population intersection without published research. Gap stands.]','2026-05-08 18:33','session_2026-05-08-co0009-phase4-pipeline-test','2026-05-09 21:04','session_2026-05-09-honest-backfill-2','Recommendation/research priority would change if cited evidence cannot be verified or if adversarial search reveals contrary published views.','30-50%','Drops with verification of cited studies; rises with adversarial search confirming no dissent.','NONE FOUND — but adversarial search not conducted at gap level. See research notes in description for shallow confirmation work.');
