INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-019','RP','P3','OPEN','functional-deficit-auditor','E-03','FDA-Q6/FDR E-03: 1:20 threshold derived from single study (Koontz 2012) for general wheelchair population. SCI-specific gradient threshold may differ (higher spinal levels have reduced propulsive capacity). FDR trigger for SCI-specific ramp research. [RESEARCH 2026-05-09: Additional evidence found beyond Koontz 2012. Yang et al.: 3° (1:20) slope produces 2.09× handrim force vs level for SCI. Japanese study: cervical SCI normalized power 0.23-0.26 W/kg on 5-8.3% slopes. Multiple biomechanics studies confirm 1:20 is achievable for most SCI users. Evidence base upgraded from SINGLE-STUDY to MODERATE (3+ independent studies, 2 with SCI populations). FDR trigger partially resolved — specific SCI C5-C6 threshold still needs validation.] [VERIFICATION 2026-05-09 23:11: Yang IS real co-author (Koontz 2005). But Yang et al. standalone with 2.09× figure NOT VERIFIED. Japanese cervical study NOT VERIFIED. Wieczorek 2014 is real but wrong population. PLOS One 2022 systematic review identified as proper primary source for re-research.]','2026-05-08 21:07','session_2026-05-08-c3-calibration','2026-05-09 23:11','session_2026-05-09-yang-verification','Recommendation would change if: (a) PLOS One 2022 systematic review concludes safe gradient differs from 1:20 for SCI populations; OR (b) Lalumiere et al. or a 2020+ meta-analysis with N>20 cervical SCI users shows 1:20 too steep OR unnecessarily conservative; OR (c) the specific 2.09× force figure cannot be verified in indexed literature (current status).','35-55%','Drops to 20-30% if specific cited figures (2.09× force, 0.23-0.26 W/kg) cannot be located in indexed literature. Rises to 65-80% if PLOS One 2022 systematic review (Lalumiere or successor) is consulted directly and confirms 1:20 falls within safe gradient envelope for SCI populations.','PARTIAL VERIFICATION: Yang IS a co-author on Koontz 2005 (J Rehabil Res Dev 42:447-458) — verified. But Yang et al. as STANDALONE citation with 2.09× figure: NOT FOUND. Japanese cervical SCI study with 0.23-0.26 W/kg: NOT FOUND. Wieczorek 2014 (Int J Ind Ergon) is real but tested 30 healthy male workers, not SCI users — population mismatch. PLOS One 2022 systematic review by Lalumiere covers slope biomechanics with 34 articles — should be primary source for any future research.');
INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-020','EC','P3','CLOSED-SYNC','economics-auditor','E-03','EA-C2 E-03: Capital cost indicator absent. Structural ramp at 1:20 is cost-significant (groundworks, drainage). Economics-researcher to supply new-build cost range. [BPC has economics (multilingual-evidence-convergence-non-english). Sync to spec.]','2026-05-08 21:07','session_2026-05-08-c3-calibration','2026-05-09 02:01:40','session_2026-05-08-bpc-crossref',NULL,NULL,NULL,NULL);
