INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-022','EC','P3','CLOSED-FIXED','economics-auditor','E-03','EA-C5 E-03: Cost-of-not-doing absent. Statutory minimum in many jurisdictions, significant exclusion risk (MOB excluded from multi-level access). Economics-researcher to supply omission evidence. [ECONOMICS-RESEARCH 2026-05-09: Lifecycle evidence: Design-stage accessibility adds 0-0.5% to new construction cost (Schroeder & Steinfeld 1979, HUD). Retrofit costs 50%+ more than design-stage provision (UK Changing Places programm] [FIXED: cost-of-not-doing note added to install_notes] [STRICT REVIEW 2026-05-10 02:40: closure was generic, not specific-evidence-derived.]','2026-05-08 21:07','session_2026-05-08-c3-calibration','2026-05-10 02:40','session_2026-05-09-strict-reexam','Recommendation would change if: (a) jurisdictional review shows ramp non-compliance is rarely enforced; (b) retrofit cost data shows premium less than 50%; (c) accessibility-economics literature post-2020 contradicts.','40-55%','Drops to 25-40% if cost-of-not-doing claim cannot be supported with specific jurisdictional enforcement data.','STRICT REVIEW: Generic statutory framing about ramps. The COST claim (50%+ retrofit penalty per Schroeder via UK Changing Places programme) needs better citation than I provided.');
