INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-260','RP','P3','OPEN','functional-deficit-auditor','K-05','THIN-BASE K-05: Item has THIN BASE flag. FDR trigger for targeted literature review. [RESEARCH 2026-05-09: Thermal Comfort Assessment — thermoregulation-impaired populations (SCI, MS) have specific evidence (Griggs 2019, MSIF 2023). BPC file exists: ms-thermal-temperature-conflict-resolution.md.] [ADVERSARIAL 2026-05-09: Griggs 2019 VERIFIED — Griggs KE et al. "Evaporative heat loss insufficient to attain heat balance at rest in individuals with a spinal cord injury at high ambient temperature." J Appl Physiol 127(4):995-1004. PMID 31414956. Also Griggs et al. 2019 infographic in Br J Sports Med 53(20):1305-1306 PMID 30610000. Loughborough/Nottingham Trent University. SCI thermoregulation impairment well-documented in systematic reviews (Freire et al. 2021 Frontiers, PMC8049141). BPC file exists in project. THIN BASE CONFIRMED — evidence real but built-environment temperature specification thresholds remain novel.] [VERIFIED: Frohman 2013 (REF-VERIFIED-011) authoritative review. Christogianni 2022 (REF-VERIFIED-010).] [REVISED 2026-05-09 23:38: Owner cross-check more rigorous than my closure. Built-environment validation is the actual gap. Reopened.]','2026-05-09 01:45','session_2026-05-08-c3-batch-all','2026-05-09 23:38','session_2026-05-09-cross-check-revision','Recommendation would change if: (a) systematic review confirms no built-environment validation studies exist; (b) direct study of MS/SCI users in temperature-controlled buildings shows thermal management not consequential; (c) clinical guidelines explicitly disclaim built-environment translation from exercise physiology data.','45-60%','Drops to 30-40% if no built-environment validation study exists for thermal thresholds. Rises to 70-80% if direct built-environment temperature specification studies emerge for SCI/MS populations.','Owner spot-check (parallel session) found: Griggs 2019 (PMID 31414956) is real but is exercise physiology, NOT built environment. Christogianni 2022 and Frohman 2013 establish thermal sensitivity but DO NOT specify built-environment temperature thresholds. Translation from exercise physiology to building specifications is an assumption.');
