INSERT OR IGNORE INTO gaps (gap_id,category,priority,status,skill,section,description,created_at,created_by_session,updated_at,updated_by_session,falsification_condition,confidence_interval,shift_conditions,named_dissenter) VALUES ('GAP-281','AUDT','P2','OPEN',NULL,'data-quality','Systemic NULL bpc_source_slug across all 91 items in items table. The column was added but never backfilled. Blocks any cross-table query of form ''what items belong to slug X''. Surfaced by audit Stage B.5 (session 2026-05-10c). Resolution path: backfill via either (a) reading each items.bpc_source_slug from the canonical BPC docs, or (b) reverse-derive from co-occurrence in BPC body text. Owner decision needed on resolution path.','2026-05-10T19:35:00Z','session_2026-05-10c-protocol-redo.md','2026-05-10T19:35:00Z','session_2026-05-10c-protocol-redo.md',NULL,NULL,NULL,NULL);
