INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','DE','SEARCHED',9,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENT: DIN 18041:2016-03 "Hörsamkeit in Räumen" (Acoustics in rooms). MEASUREMENT CONDITION: OCCUPIED room (80% of nominal occupancy) — critical methodological note. THRESHOLDS by room type (Gruppe A, volumes up to ~250m³): Standard classroom (Unterrichtsraum): RT 0.5–0.6s. Inclusion classroom/hearing-impaired students/foreign-language learners (Inklusionsklassen, Hörgeschädigte): RT ≤0.4s. Minimum lower bound: RT ≥0.4s (below this over-dampening causes problems for normal hearing students). Volume-dependent: uses volumenkennzahl k factor (Table 4) for precise frequency-band targets. Measurement: DIN EN ISO 3382. CRITICAL DIVERGENCE from UK (BB93): DE specifies occupied RT; UK specifies unoccupied RT. UK general classroom ≤0.8s unoccupied ≠ DE 0.5–0.6s occupied — these are NOT directly comparable. For hearing-impaired: UK ≤0.4s unoccupied vs DE ≤0.4s occupied — same number, different measurement state; effectively different requirements. Sources: sichere-schule.de, fennext.eu/din-18041, DGUV, GEW-BW. CONFIDENCE: high for thresholds and occupied/unoccupied distinction; high for 0.4s hearing-impaired threshold.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:41:09.126863+00:00','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','FR','PARTIAL',5,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: NF S31-080:2006 (AFNOR, "Acoustique — Bureaux et espaces associés — Niveaux et critères de performances acoustiques par type d''espace"), covers schools, offices, healthcare. Code de la construction et de l''habitation (general acoustic requirements). STRUCTURE: NF S31-080 prescribes RT by room type in three voluntary performance levels: Courant (standard minimum), Performant (improved), Très Performant (excellent). Volume-dependent RT targets (similar to DIN 18041 Volumenkennzahl approach). General reference: 0.5s mentioned as reference duration in French building regulations (Siniat source). REGULATORY STATUS: CRITICAL DIVERGENCE from UK — NF S31-080 is a voluntary norm (not legally mandatory); Code de la construction sets general principles but delegates specifics to voluntary norms. UK BB93 has legal force under Building Regulations — NF S31-080 does not. HEARING IMPAIRED: French disability law (Loi 2005) requires "accessibilité sonore" for ERP including hearing-impaired access; specific RT threshold for hearing-impaired classrooms not retrieved. Arrêté du 1er août 2006 covers acoustic elements of accessibility qualitatively. GAP: Specific NF S31-080 RT values for school classrooms by performance level — not retrieved. Specific hearing-impaired classroom RT threshold — not retrieved. Sources: decibelfrance.com, acoustiques-solutions.fr, renergise.fr (reglementation). CONFIDENCE: high for voluntary/regulatory structural distinction; medium for absence of specific values.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:02:35.914297+00:00','session_2026-05-11c-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','DA','SEARCHED',7,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: Arbejdstilsynet requirements (Danish Working Environment Authority, school-specific noise regulations since 2008), BR18/Bygningsreglementet, Arbejdsmiljøbekendtgørelse on schools. Supporting guidance: DCUM (Dansk Center for Undervisningsmiljø). STRUCTURE: Two-tier (general / special). THRESHOLDS: General classrooms (klasseværelser til normalundervisning): RT ≤0.6s — mandatory for buildings permitted since 2008; older buildings: ≤0.9s (legacy threshold). Special education rooms (specialundervisning), group work areas: RT ≤0.4s. Day care/SFO (fritidsordninger/skolefritidsordninger): RT ≤0.4s. Stairwells, other school areas: separate values (not specified in retrieved text). DCUM RECOMMENDATION: ≤0.4s for all classrooms (advocacy beyond mandatory minimum, citing child hearing research showing 6-year-olds perceive only half as many sentences as 12-year-olds in high background noise). CRITICAL DIVERGENCES: (1) DA general classroom 0.6s matches NO (≤0.6s Klass C) but is less strict than SV (≤0.5s SS 25268). (2) DA ≤0.6s is significantly stricter than UK ≤0.8s unoccupied — but occupied/unoccupied distinction makes this partially methodological. (3) DA two-tier structure (0.6s / 0.4s) mirrors DE (0.5-0.6s occupied / 0.4s occupied) but DA measurement condition unknown. (4) DCUM advocacy for ≤0.4s universal suggests professional consensus toward the lower threshold even for general classrooms. Sources: godtarbejdsmiljo.dk/love-og-regler-saerligt-boern-og-unge, indeklimaportalen.dk/akustikregulering. CONFIDENCE: high for ≤0.6s and ≤0.4s thresholds; medium for exact regulatory instrument reference (Arbejdstilsynet order number not retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:57:36.397139+00:00','session_2026-05-11b-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','FI','PARTIAL',5,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: Suomen rakentamismääräyskokoelma (RakMK) osa C1 (Building Regulations, acoustics section — legally binding); SFS 5907 (Rakennusten akustinen luokitus — Building Acoustic Classification standard, 4 classes A-D; class C referenced by indoor climate class S2). THRESHOLDS: RakMK C1 regulatory maximum: RT <0.8s for classrooms. SFS 5907 Klass C (minimum standard level, referenced in indoor climate requirements for schools): recommends shorter RT than RakMK C1 — approximately 0.5s target cited by practitioners for speech intelligibility. Open learning spaces: 0.6s design value cited as good, 0.4s as better. Speech intelligibility: 0.5s consistently cited as the threshold above which speech intelligibility begins to degrade. HEARING IMPAIRED: No specific separate building regulation RT criterion for hearing-impaired classrooms found. CRITICAL DIVERGENCES: (1) FI building regulation maximum 0.8s matches UK BB93 general (≤0.8s unoccupied) and FI building regulation (RakMK C1) — both unoccupied. (2) SFS 5907 Klass C recommendation (~0.5s) is stricter than RakMK C1, similar to SV mandatory (≤0.5s SS 25268 grundläggande) and DA minimum (≤0.6s). (3) Distinction between RakMK regulatory maximum (0.8s) and SFS 5907 recommended value (shorter) matters for batch synthesis — citing 0.5s as regulatory when it''s recommended level would be wrong. GAP: Specific SFS 5907 Klass C RT table value for school classroom size category — not retrieved. Hearing-impaired specific RT not retrieved. Sources: akustinenseura.fi/SFS-5907, theseus.fi/koulurakennuksen-aanitekniikka, akulux.fi. CONFIDENCE: high for 0.8s RakMK ceiling; medium for SFS 5907 ~0.5s recommendation (implied, not directly retrieved from standard text).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:07:33.790253+00:00','session_2026-05-11c-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','EN','SEARCHED',11,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: UK — BB93:2015 (Building Bulletin 93, "Acoustic Design of Schools: Performance Standards"), legally required under Building Regulations Approved Document E. US — ANSI S12.60:2010. MEASUREMENT CONDITION: UNOCCUPIED rooms (critical methodological distinction from DE which uses occupied). UK THRESHOLDS (BB93:2015, mid-frequency Tmf): Standard classrooms — ≤0.8s unoccupied. Classrooms specifically designed for hearing-impaired/deaf pupils and SHCN (Special Hearing and Communication Needs): ≤0.4s unoccupied. Dining rooms: ≤1.0s. Background noise criteria for SHCN classrooms: ≤30 dBA LAeq,30min. Legal basis: Equality Act 2010 + School Premises Regulations 2012. US THRESHOLD (ANSI S12.60:2010): ≤0.6s for rooms ≤283m³; ≤0.7s for rooms 283–566m³ (unoccupied). CRITICAL DIVERGENCE: (1) UK and US both specify unoccupied; DE specifies occupied — values not directly comparable. (2) UK general classroom 0.8s is significantly more permissive than DE 0.5-0.6s occupied; this difference is partly methodological (occupied vs unoccupied) — not purely a regulatory difference. (3) UK''s 0.4s SHCN = DE''s 0.4s hearing-impaired — same target value but different measurement conditions mean UK effectively allows more RT. (4) US ANSI S12.60 0.6s is more restrictive than UK 0.8s for general classrooms. Sources: BB93:2015 (UK government, gov.uk), BATOD acoustic standards guidance, NOVA Acoustics, IOA proceedings (Greenland & Shield). CONFIDENCE: high for all UK values; high for ANSI S12.60 values.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:41:09.126863+00:00','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','ES','SEARCHED',8,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENT: CTE DB-HR (Documento Básico de Protección frente al Ruido, Código Técnico de la Edificación) — legally binding for buildings with municipal construction permit after 23.10.2008. CLASSROOM RT: ≤0.5s mandatory for aulas and conference rooms (measured empty including all seats, average 500Hz/1kHz/2kHz), for volume <350m³. Restaurants/canteens: ≤0.9s. Exception: classrooms with volume >350m³ require individual acoustic study. Alternative compliance: absorption equivalent area A ≥ 0.2m²/m³ of room volume (simplified method via absorptive ceiling). HEARING IMPAIRED: No separate specific RT threshold for hearing-impaired classrooms in CTE DB-HR — single-tier regulation applies uniformly. CRITICAL DIVERGENCES: (1) ES ≤0.5s (empty + seats) aligns with SV ≤0.5s (SS 25268, unoccupied) — same measurement condition and same value. Both stricter than UK general ≤0.8s. (2) ES has NO separate hearing-impaired classroom RT provision unlike UK (SHCN ≤0.4s), DE (≤0.4s occupied), DA (≤0.4s special education). (3) ES measurement: empty + seats (unoccupied equivalent) — comparable to UK and SV, not to DE (occupied). (4) CTE DB-HR Annex J provides acoustic design recommendations for aulas — not binding additional requirements. Sources: sontect.com/tiempo-de-reverberacion-normativa, retokommerling.com/DB-HR, codigotecnico.org/DBHR.pdf, acusticaescolar.com. CONFIDENCE: high — primary CTE DB-HR §2.2 text confirmed from multiple practitioner sources and primary document.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:07:33.790253+00:00','session_2026-05-11c-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','ZH','PARTIAL',5,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENT: GB 50118-2010《民用建筑隔声设计规范》(Code for Sound Insulation Design of Civil Buildings, Ministry of Housing and Urban-Rural Development, effective 2011-06-01). Applies to schools (学校) among six building types. Chapter on school buildings (§ on school sound insulation, page 14 per practitioner annotation) addresses classroom acoustics. WHAT WAS RETRIEVED: (1) GB 50118-2010 covers school classroom RT — confirmed by Zhihu source citing page 14 with discussion of appropriate RT and uniform sound field as fundamental requirements for classroom hearing conditions. (2) Mandatory articles (强制性条文): §4.1.1, §4.2.1, §4.2.2, §4.2.5 — these address residential insulation, not schools. School RT requirement likely not a mandatory article. (3) GB 55016-2021《建筑环境通用规范》(Building Environment General Code) may have updated school acoustic requirements. WHAT WAS NOT RETRIEVED: Specific classroom RT value in GB 50118-2010 §school chapter. Hearing-impaired specific classroom RT requirement. GAP: GB 50118-2010 page 14 specific RT value for schools; GB 55016-2021 school acoustic provisions. Sources: bzko.com/GB50118, gongbiaoku.com, zhihu.com/p/678088489 (page 14 interpretation). CONFIDENCE: high for framework existence; low for specific value (not retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:05:48.017086+00:00','session_2026-05-11c-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','IT','SEARCHED',8,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: Circolare Ministero Lavori Pubblici n. 3150 del 22 maggio 1967 (Criteri di valutazione e collaudo dei requisiti acustici negli edifici scolastici); DPCM 5 dicembre 1997 (Determinazione dei requisiti acustici passivi degli edifici, legally binding since 20 Feb 1998); DM 18 dicembre 1975 (provides volume-based optimal RT at 500Hz). UNI 11532-2:2020 (newer standard on school acoustic quality — not necessarily legally binding). CLASSROOM RT: Average RT (250, 500, 1000, 2000 Hz) ≤1.2s — for furnished classrooms with ≤2 persons. This is the DPCM 1997 requirement for category E buildings (educational). Gyms: ≤2.2s (if not used as auditorium). CRITICAL DIVERGENCE — MOST PERMISSIVE IN SET: IT''s ≤1.2s is dramatically higher than all other jurisdictions: DE ≤0.5-0.6s (occupied general), UK ≤0.8s (unoccupied general), NO ≤0.6s, SV ≤0.5s, DA ≤0.6s, ES ≤0.5s. The 1967 circular''s threshold reflects older acoustic research standards. Measurement condition: furnished + ≤2 persons (unique specification, intermediate between UK unoccupied and DE occupied). HEARING IMPAIRED: No specific separate RT criterion for hearing-impaired classrooms found in DPCM 1997. UNI 11532-2:2020 may have better provisions — not retrieved. Sources: anit.it/dpcm-5-12-1997, poroton.it, biblus.acca.it, ingenio-web.it/UNI-11532-2. CONFIDENCE: high for 1.2s threshold from confirmed DPCM 1997 + Circolare 1967 text; medium for absence of separate hearing-impaired provision.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:09:02.923343+00:00','session_2026-05-11c-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','KO','PARTIAL',2,'TIER2 2026-05-11. NOT SEARCHED for KO deaf-classroom specifically. From prior KO research: primary accessibility instrument is 장애인·노인·임산부 등의 편의증진 보장에 관한 법률 (Disability Convenience Act). That law covers physical accessibility (ramps, elevators, toilet dimensions) but may not cover classroom acoustic RT requirements. KR building code acoustic standards are likely separate from disability convenience law. GAP: Korean building code acoustic standard for schools and specifically for hearing-impaired classrooms — not searched. CONFIDENCE: low — no search conducted for this language/slug combination.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:15:46.948011+00:00','session_2026-05-11d-tier2-final');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','SV','SEARCHED',7,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: BBR avsnitt 7:22 (Boverkets byggregler, section on lokaler/premises — legally binding), SS 25268 (Byggakustik – Ljudklassning av utrymmen i byggnader – Vårdlokaler, undervisningslokaler, dag- och fritidshem, kontor och hotell; revised 2023). BBR references SS 25268 as the standard for minimum requirements for schools. STRUCTURE: SS 25268:2023 changed from four classes (A, B, C, D) to two levels: "grundläggande krav" (basic requirements, ~= former Klass C, minimum) and "utökade krav" (extended requirements). THRESHOLDS: General classroom (undervisningsrum): RT ≤0.5s (SS 25268 grundläggande krav; confirmed by multiple practitioner sources citing BBR/SS 25268 requirement). Hearing-impaired/hearing-sensitive rooms: Background noise tightened in 2023 revision from ≤30dBA to ≤25dBA LpAeq and ≤45dB LpCeq; RT threshold for hearing-impaired rooms not directly retrieved this session. Stairwells in schools: ≤0.8s (tightened from 1.2s). CRITICAL DIVERGENCES: (1) SV ≤0.5s general classroom is stricter than NO (≤0.6s Klass C) and UK general (≤0.8s unoccupied) — but measurement condition for SV/UK (unoccupied) vs DE (occupied) means not directly comparable. (2) SV 2023 revision moved to two-level grundläggande/utökade structure — batch synthesis using pre-2023 A/B/C/D framework is now outdated. (3) Unlike NO (which elevated hearing-impaired criteria to all users in 2012), SV maintains separate stricter criteria for hearing-impaired rooms. Sources: boverket.se/PBL-kunskapsbanken/bullerskydd/ljudklassning, absoflex.se/skolmiljo, goteborg.se (Gothenburg specification RA-1897), sis.se/fragor-och-svar-pa-ss-25267. CONFIDENCE: high for 0.5s general classroom; medium for hearing-impaired specific RT value (background noise confirmed, RT not directly retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:56:44.310618+00:00','session_2026-05-11b-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','NL','SEARCHED',7,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENT: Programma van Eisen Frisse Scholen 2015 v3 (Programme of Requirements for Fresh Schools, commissioned by Ministerie van Binnenlandse Zaken) — policy guideline, not legally mandated like UK BB93 or DE DIN 18041. Supporting: Bouwbesluit 2012 (sets general acoustic requirements). STRUCTURE: Three-tier system for classroom RT (measured in furnished classroom — ingerichte leslokaal): Klasse C (voldoende/acceptable): RT ≤0.8s; Klasse B (goed/good): RT ≤0.6s plus 125Hz octave ≤30% deviation; Klasse A (uitmuntend/excellent): RT ≤0.4s. Additional Frisse Scholen norm: rooms with ≥30 students or circulation spaces: RT ≤0.8s (min. Klass C). All requirements must be met for ≥95% of use time. HEARING IMPAIRED: No specific separate RT criterion for hearing-impaired classrooms retrieved. Klasse A (0.4s) would represent hearing-impaired appropriate level but not specified as such. CRITICAL DIVERGENCES: (1) NL measurement: furnished classroom (similar to DE, IT, ES) — NOT unoccupied like UK, SV. Makes NL Klass C (0.8s furnished) less directly comparable to UK (0.8s unoccupied). (2) Frisse Scholen is guideline not mandatory — structural difference from legally binding UK BB93 or DE DIN 18041. (3) Three-tier system similar to pre-2023 SV SS 25268, unlike DA two-tier. (4) Klasse A (0.4s) matches UK SHCN and DE hearing-impaired thresholds. Sources: acoustinorm.nl, akoestiekmeesters.nl, allkoestiek.nl/frisse-scholen. CONFIDENCE: high for Klass A/B/C values and measurement condition; medium for regulatory status (policy vs law distinction).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:09:02.923343+00:00','session_2026-05-11c-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','PT','PARTIAL',2,'TIER2 2026-05-11. NOT SEARCHED for PT deaf-classroom specifically. From prior PT research: DL 163/2006 covers accessibility primarily for mobility. Classroom acoustic standards would come from separate Portuguese building regulations or INR guidance. Specific classroom RT requirements for hearing-impaired students in Portugal not searched. GAP: Portuguese school acoustic standard and specific classroom RT for hearing-impaired — not retrieved. CONFIDENCE: low — no search conducted for this language/slug combination.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:15:46.948011+00:00','session_2026-05-11d-tier2-final');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','NO','SEARCHED',9,'TIER2 NATIVE SEARCH 2026-05-11 (upgrading from PARTIAL). KEY INSTRUMENT: NS 8175 (Norsk Standard "Lydforhold i bygninger — Lydklasser for ulike bygningstyper"), editions 2008, 2012, 2019. TEK17 references NS 8175:2012 as legally binding minimum requirement (Klasse C). STRUCTURE: Four sound classes A (best) through D (worst). Klasse C = TEK17 minimum. THRESHOLDS for undervisningsrom (classrooms): Lydklasse C ≤0.6s; Lydklasse B ≤0.5s (NTNU kravspesifikasjon uses Klasse B as university standard); Lydklasse A ≤0.3s (best practice). CRITICAL UNIVERSELL UTFORMING PROVISION (NS 8175:2012 revision): The revised 2012 standard applied the previously hearing-impaired-specific RT criteria to ALL rooms, under the universell utforming principle. This is structurally different from DE (separate category for hørselshemmede) and UK (separate SHCN category with dedicated ≤0.4s threshold) — NO effectively collapsed the distinction by raising the baseline for everyone. NS 8175:2019 version carries this forward but not yet legally binding (DiBK konsekvensanalyse pending as of 2019). Background noise for hearing impaired: 22dBA (Lydklasse A) specified in NS 8175. CRITICAL DIVERGENCE: (1) NO uses a tiered class system (not single threshold); (2) NO''s universell utforming approach merges hearing-impaired and general criteria at the Klasse A level; (3) Klasse C general threshold ≤0.6s is consistent with US ANSI S12.60 but less strict than DE''s 0.5-0.6s for standard rooms (noting occupied vs unoccupied distinction still applies). Sources: Standard Norge lydklasser page, NS 8175 og universell utforming presentation (docplayer), Bufdir hørselsvennlig miljø, NTNU kravspesifikasjon akustikk. CONFIDENCE: high for class structure and 0.6s Klasse C; medium for precise Klasse A value (0.3s from NS 8175 table — not directly retrieved from standard text).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:42:09.925564+00:00','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('deaf-classroom-reverberation-time','JA','PARTIAL',5,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENT: 学校施設整備指針 (School Facilities Development Guidelines, MEXT — Ministry of Education). CRITICAL STRUCTURAL DIVERGENCE: Japan lacks a legally binding national building regulation specifically mandating classroom reverberation time, unlike UK (BB93 under Building Regulations), DE (DIN 18041 incorporated into LTB), SV (SS 25268 under BBR), DA (Arbejdstilsynet regulation), or NO (NS 8175 under TEK17). Instead, MEXT provides advisory 学校施設整備指針 (guidelines to which school owners "should pay sufficient attention" — 十分配慮すること, not mandatory compliance). GUIDANCE LEVEL: Nursery/childcare facilities: RT recommended 0.4s introduced 2020 (for room approx. 50m², h=2.5m). School classrooms: specific RT value in 学校施設整備指針 not retrieved; guidelines address 音環境 (acoustic environment) qualitatively — absorptive ceilings, wall panels, furniture placement. Hearing-impaired support: MEXT guidance addresses collective hearing aids (FM/IR systems, loop systems) for hearing-impaired students rather than RT-specific requirements. The absence of a mandatory RT standard is itself a critical finding — batch synthesis claiming a specific mandatory Japanese classroom RT would be fabricating or misattributing a guideline value. Sources: MEXT (mext.go.jp/a_menu/shisetu), hoiku-otokankyo.org (nursery 0.4s guidance). CONFIDENCE: high for structural finding (advisory vs mandatory); medium for absence of specific school RT in guidelines (may exist in guideline text not retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T03:02:35.914297+00:00','session_2026-05-11c-tier2-continued');
