INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','DE','SEARCHED',8,'TIER2 NATIVE SEARCH 2026-05-11. Key instrument: DIN 32975:2009-12 (Gestaltung visueller Informationen) + DIN 18040-1/2/3. Metric: Michelson formula K=(L1-L2)/(L1+L2). Thresholds: K≥0.4 (orientation elements, handrails, floor markings, general contrast — "visuell kontrastierend") and K≥0.7 (signage, text, emergency/warning elements — "visuell stark kontrastierend"); K≥0.8 target for black/white combinations. Additional constraint: lighter surface must have reflectance ρ≥0.5 (approx. LRV 50). DIN 32975 not adopted as Technical Building Requirement in all Länder (unlike DIN 18040-1/2 which is incorporated into LTB). DIN 18040-3:2014 explicitly uses "visuell kontrastierend" (K≥0.4) and "visuell stark kontrastierend" (K≥0.7) as defined terms. CRITICAL DIVERGENCE: DE uses Michelson K metric, not LRV difference (UK BS8300) — not directly comparable without conversion tables. Sources: nullbarriere.de/din32975 (DBSV), Brillux, ift-rosenheim, DBSV 2016 Broschüre. CONFIDENCE: high for metric and thresholds; medium for current adoption status per Bundesland.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:33:33.562206','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','FR','SEARCHED',7,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: Loi du 11 février 2005, Décret n° 2006-555 du 17 mai 2006, Arrêté du 1er août 2006 (ERP neufs), Arrêté du 8 décembre 2014 and Arrêté du 20 avril 2017 (ERP existants). CONTRAST STRUCTURE: Two-tier. (1) Primary regulation: qualitative only — "contraste visuel suffisant" (sufficient visual contrast) in Arrêtés; no numerical value in primary law. (2) Technical norms: NF P98-351 (bandes d''éveil à la vigilance/BEV tactile warning strips) and NF P98-352 (bandes de guidage) specify ≥70% luminance contrast between strip and adjacent surface. METRIC: luminance contrast using a formula consistent with Weber contrast or simple luminance ratio — French sources describe "contraste positif" (LBEV > Lsupport) as ranging from 0 to infinity and "contraste négatif" (BEV darker) from 0 to 1. One practitioner source mentions delta LRV ≥30% as minimum, ≥70% recommended for stair nosings — suggesting LRV awareness but not primary regulatory metric. CRITICAL DIVERGENCE: (1) FR''s 70% NF P98-351 threshold applies specifically to guidance/warning strips, not general building surfaces. (2) French primary regulation is qualitative; specific values come from technical norms (NF), not legally binding Arrêté text. (3) FR metric (luminance ratio/Weber) differs from UK (LRV points), DE (Michelson K), SV (NCS lightness). Sources: handinorme.com, prozon.com (NF P98-351 formula), espritdentreprise.com, cerema.fr. CONFIDENCE: high for qualitative regulatory structure and BEV 70% threshold; medium for general surface requirements (qualitative confirmed; precise NF norm text for general surfaces not retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:52:00.279539+00:00','session_2026-05-11b-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','DA','SEARCHED',5,'TIER2 NATIVE SEARCH 2026-05-11. Key instrument: BR18 (Bygningsreglementet 2018). CRITICAL DIVERGENCE from DE/NO/SV: BR18 uses functional requirements (funktionskrav), not prescriptive numerical contrast values in the primary legislation. Specific values come from SBi-anvisning 272 (which interprets BR18) and referenced standards DS/ISO 21542:2012 and DS/EN 17210. BR18 uses belægningsskift (surface change) language; specific contrast threshold (e.g., 0.4 luminanskontrast) appears in SBi guidance and outdoor area requirements aligned with Nordic norms but is not a legally mandated number in BR18 itself. DS/EN 17210 and DS/ISO 21542 can be contractually required by clients but are not legally mandatory. Source: tibs.blind.dk, rumsans.dk, bygningsreglementet.dk, dansk standard. CONFIDENCE: high for function-based structure; medium for specific SBi 272 contrast figure (not directly retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:33:33.562206','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','FI','PARTIAL',3,'TIER2 NATIVE SEARCH 2026-05-11. Key instrument: Decree 241/2017 (Asetus rakennuksen esteettömyydestä) under Maankäyttö- ja rakennuslaki. Governing body: Ympäristöministeriö. Searches returned the decree framework and Ympäristöministeriö guidance document (2018) but specific luminance/luminanssikontrast numerical thresholds not retrieved in this session. Helsinki esteettömyyssanakirja references luminanssikontrasti as a concept. FI likely aligns with Nordic range (0.40) but specific regulatory value needs direct decree text review. GAP: Finnish building code accessibility decree Chapter on visual contrast — specific threshold value not confirmed.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:33:33.562206','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','EN','SEARCHED',12,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: UK — BS 8300-2:2018 (code of practice) + Approved Document M (Part M, Building Regulations, legally binding). Ireland — TGD Part M (Technical Guidance Document). USA — ADA Standards for Accessible Design. Metric: UK/IE use LRV (Light Reflectance Value, scale 0–100, measured per BS 8493:2008+A1:2010). THRESHOLDS: General/stair nosings ≥30 LRV points difference; large areas (wall/floor) ≥20 points if illuminance ≥200 lux; door opening furniture ≥15 points (3D form relaxation). Approved Document M defines ''contrast visually'' as LRV difference >30 points. ADA: qualitative only — ''light characters on dark background or dark characters on light background'' — no specific LRV or Michelson threshold. CRITICAL DIVERGENCE: UK uses LRV difference; DE uses Michelson K; SV uses NCS lightness difference. Not directly equivalent. UK LRV 30 ≠ DE Michelson 0.4. Sources: BS 8300-2:2018, Approved Document M, Building Regulations Part M, Equality Act 2010, Gradus guide, Carlisle Brass LRV guide. CONFIDENCE: high for UK/IE; high for ADA qualitative position; medium for equivalence between metric systems.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:34:06.893588+00:00','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','ES','PARTIAL',5,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENT: CTE DB SUA (Código Técnico de la Edificación, Documento Básico de Seguridad de Utilización y Accesibilidad) — legally binding, governed by Real Decreto 314/2006 as amended by Real Decreto 173/2010. CONTRAST: DB SUA 9 (Accesibilidad section) uses "contraste cromático" (chromatic contrast) for signage/door numbering/tactile strips — qualitative language without specific luminance contrast numerical threshold in primary CTE DB SUA text retrieved. Visual/tactile strips must be "de color contrastado con el pavimento" (color contrasted with pavement) with relief height 3±1mm interior, 5±1mm exterior. No LRV, Michelson, or other quantified contrast requirement found in primary CTE text. BONUS FINDING FOR STAIR-RAMP SLUG: CTE DB SUA 9 ramp gradients use length-tiered table: ≤12% for ≤3m, ≤8% for 3-6m, ≤6% for 6-9m, ≤4% exceptional. This is a third distinct length-tiered table alongside UK (1:20/1:15/1:12) and differs from DE (single 6%/10% exception). GAP: Specific LRV or luminance contrast value in CTE DB SUA for general building surfaces — not retrieved. Sources: codigotecnico.org/DcmSUA.pdf, verificacioncte.es, vitoria-gasteiz.org/dbsua-criteria. CONFIDENCE: high for qualitative structure; medium for absence of specific value (may exist in CTE technical annexes not retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:53:14.624085+00:00','session_2026-05-11b-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','ZH','SEARCHED',6,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: GB 50763-2012《无障碍设计规范》(Accessibility Design Code, Ministry of Housing and Urban-Rural Development, effective 2012-09-01), supersedes JGJ 50-2001. Also: JGJ 450-2018《老年人照料设施建筑设计标准》(elderly care facilities, already in DB from Tier 1 validation). CONTRAST REQUIREMENTS: GB 50763-2012 uses qualitative language only — for stairs: 踏面和踢面的颜色宜有区分和对比 (treads and risers ''should have color differentiation and contrast'') and 楼梯上行及下行的第一阶宜在颜色或材质上与平台有明显区别 (first step should clearly differ in color or material from platform). No specific numerical luminance contrast value specified in standard text retrieved. 宜 (should/advisable) formulation throughout — not 应/必须 (mandatory). CRITICAL DIVERGENCE: China''s primary accessibility code uses qualitative requirements without numerical threshold, in sharp contrast to DE (Michelson K 0.4/0.7), NO (luminanskontrast 0.4/0.8), SV (NCS 0.40), UK (LRV ≥30). Any batch synthesis claiming a specific Chinese luminance contrast ratio would be fabricated or drawn from a secondary source. Note: GB 50763-2012 may be superseded by later standards (2021 revision reported for 建筑设计标准); specific post-2021 ZH contrast threshold not retrieved. GAP: post-2021 revision of ZH accessibility standard — specific contrast provisions not confirmed. Sources: GB 50763-2012 full text (multiple repositories), Zhihu annotation. CONFIDENCE: high for qualitative nature of GB 50763-2012 requirements; medium for whether post-2021 revision added numerical thresholds.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:36:11.195088+00:00','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','IT','PARTIAL',4,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: DM 236/89 (Decreto Ministeriale 236/1989 — private buildings), DPR 503/1996 (public buildings and public spaces). CONTRAST: Primary regulatory instruments use qualitative language for visual contrast — "contrasto di luminanza" referenced as concept in the context of tactile guidance strips and crossings (ITACA draft regulation), but no specific numerical luminance contrast threshold found in DM 236/89 or DPR 503/1996 primary text. Reference to "contrasto visivo" and "contrasto di luminanza" in accessible design guidance documents. Italy is EU member state — EN 17210 is available as European guidance but not directly incorporated into national building code by law. GAP: post-2018 revision of Italian accessibility regulations — if any specific luminance contrast values were added in recent legislative updates, not retrieved. Sources: mobilitaautonoma.org, cedingegneria.it/DM-236-89, ITACA draft. CONFIDENCE: high for qualitative nature of primary regulation; medium for absence of specific value (gap possible).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:53:14.624085+00:00','session_2026-05-11b-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','KO','PARTIAL',4,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENT: 장애인·노인·임산부 등의 편의증진 보장에 관한 법률 (Act on Ensuring Convenience for Persons with Disabilities, the Elderly, and Pregnant Women) and its implementation rules (시행규칙, 별표 1 — Annex 1). CONTRAST: Primary regulation covers structural and dimensional requirements for accessibility facilities (ramps, elevators, tactile guidance strips, toilet facilities). Visual/tactile guidance strips required with contrast to surrounding pavement — qualitative. No specific luminance contrast numerical threshold (휘도 대비 값) found in the retrieved implementation rules text. Korean building code may reference KS (Korean Industrial Standards) for contrast specifications — not retrieved. GAP: KS standards for luminance contrast in buildings; specific numerical value in 별표 1 or KS equivalent not confirmed. Sources: law.go.kr (별표 1), easylaw.go.kr, Ministry of Health and Welfare. CONFIDENCE: high for qualitative regulatory structure; medium for absence of specific value (KS standard reference may contain numerical requirement).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:54:16.511058+00:00','session_2026-05-11b-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','SV','SEARCHED',7,'TIER2 NATIVE SEARCH 2026-05-11. Key instruments: BBR (BFS 2011:6) now transitioning to BFS 2024:12 (from 1 July 2025; transition period until 30 June 2026). Metric: NCS ljushetskontrast ≥0.40 for all contrast markings (kontrastmarkeringar) per BBR avsnitt 3:1. CRITICAL DIVERGENCE: SV uses NCS lightness difference (ljushetskontrast), not Michelson K (DE) or LRV difference (UK). NCS lightness ≥0.40 ≈ meaningful difference in NCS S-notation second value, but not directly equivalent to LRV 30 or Michelson 0.4. New rules BFS 2024:12 — contrast requirements carried over but wording revised. Sources: Boverket (boverket.se/kontrastmarkering), MFD. CONFIDENCE: high for ≥0.40 NCS threshold; medium for BFS 2024:12 exact wording (not retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:33:33.562206','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','NL','PARTIAL',4,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: Bouwbesluit 2012 (primary building regulation — legally binding), NEN 1814:2001 "Toegankelijkheid van buitenruimten, gebouwen en woningen" (standard — NOT legally binding), NEN 9120:2025 "Prestatie-eisen voor toegankelijkheid en bruikbaarheid van gebouwen" (new standard published Feb 2025 — adoption status in Bouwbesluit unclear). CONTRAST: Bouwbesluit 2012 has minimal specific contrast requirements (mainly functional: wheelchair routes, accessible toilets). Specific luminance contrast numerical value not found in legally binding Bouwbesluit text. NEN 1814 contains detailed accessibility requirements including contrast but is not incorporated into Bouwbesluit by law ("De norm is niet opgenomen in de wetgeving"). NEN 9120:2025 may contain contrast requirements but text not retrieved. CRITICAL DIVERGENCE from DE: German DIN 32975 is incorporated into LTB = legally binding; Dutch NEN 1814 is not legally binding. The practical situation is similar to DA (BR18 functional, detail in non-binding SBi). GAP: NEN 9120:2025 specific contrast provisions — not retrieved. Sources: nen.nl, publicspaceinfo.nl, bouwbesluitonline.nl. CONFIDENCE: high for regulatory structure (non-binding NEN vs binding Bouwbesluit); medium for absence of specific value (may exist in NEN 9120:2025 not retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:52:00.279539+00:00','session_2026-05-11b-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','PT','PARTIAL',4,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENT: Decreto-Lei n.º 163/2006, de 8 de agosto (regime da acessibilidade, accessibility legal regime), as amended by Decreto-Lei n.º 125/2017. Technical standards in Annex (normas técnicas). INR (Instituto Nacional para a Reabilitação) is the governing body. CONTRAST: DL 163/2006 primary text uses accessible route and facility language; specific luminance contrast (contraste de luminância) numerical threshold not found in the primary article text retrieved. INR publication "Acessibilidade e Mobilidade para Todos" (280 pp.) likely contains specific technical guidance — not retrieved. GAP: Annex to DL 163/2006 specific contrast provisions and INR guidance publication — specific numerical luminance contrast value not confirmed. Note: PT is EU member — EN 17210 available as guidance; given linguistic proximity to Spanish, ES CTE qualitative approach may be similar. Sources: pgdlisboa.pt/DL163-2006, inr.pt, cm-vfxira.pt (revision document). CONFIDENCE: high for regulatory framework; low for specific contrast value (not retrieved).','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:54:16.511058+00:00','session_2026-05-11b-tier2-continued');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','NO','SEARCHED',9,'TIER2 NATIVE SEARCH 2026-05-11. Key instrument: TEK17 (Byggteknisk forskrift) §8-6, §12-4, §12-6, §12-9, §12-14. Standard: NS 11001:2018 (Universell utforming av byggverk). Thresholds: luminanskontrast 0.4 for access paths (§8-6), floor/wall in bathrooms (§12-9), general orientation elements in communication paths (§12-6); luminanskontrast 0.8 for stair treads, handrails, danger fields before stairs, signage (§12-14 and §12-6). CRITICAL DIVERGENCE from DE: NO requires 0.8 for stairs vs DE''s K≥0.7; NO''s scale also differs from DE Michelson — formula equivalence unclear. NCS colour system used for LRV compliance documentation (NCS Lyshetstabell). Source: dibk.no (official Norwegian Building Authority), fagflis.no, evaculine.no, universellutforming.no. CONFIDENCE: high — DiBK is primary regulatory source.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:33:33.562206','session_2026-05-11a-tier2-multilingual');
INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('luminance-contrast-and-pattern','JA','SEARCHED',8,'TIER2 NATIVE SEARCH 2026-05-11. KEY INSTRUMENTS: バリアフリー法 (Barrier-Free Promotion Act 2006), 建築設計標準 (Architectural Design Standard, MLIT), 道路の移動等円滑化整備ガイドライン (Road Mobility Guideline). Metric: 輝度比 (luminance ratio = L1/L2 where L1>L2) — NOT Michelson K, NOT LRV difference. THRESHOLD: 輝度比 ≥ 2.0 for 視覚障害者誘導用ブロック (tactile guidance blocks) — from Road Mobility Guideline citing existing research showing 1.5-2.5 acceptable range; 2.0 chosen as standard. Legal basis for guidance blocks: バリアフリー法 requires 輝度比が大きい (large luminance ratio) without specifying a number; 2.0 is in the guideline (望ましい = desirable), not the Act itself. Building general surfaces (walls, floors, doors): specific threshold value not retrieved from 建築設計標準 — likely qualitative or references 輝度比 concept without fixed number. CRITICAL DIVERGENCE: (1) Japan uses ratio metric (L1/L2), not LRV points difference or Michelson K — not directly convertible without careful calculation; (2) Regulatory threshold (2.0) is guideline-level望ましい, not Act-level mandatory; (3) Tactile block guidance is primary context — built surface general contrast less precisely specified. Sources: 道路の移動等円滑化整備ガイドライン (MLIT/国土技術研究センター), 太平洋プレコン工業 product spec, Wikipedia 視覚障害者誘導用ブロック. CONFIDENCE: high for metric (輝度比) and guidance block threshold (2.0); medium for applicability to general building surfaces.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11T02:36:11.195088+00:00','session_2026-05-11a-tier2-multilingual');
