INSERT OR IGNORE INTO search_languages (slug,language,status,results_count,notes,created_at,created_by_session,updated_at,updated_by_session) VALUES ('visual-fire-alarm-seizure-safety','ZH','SEARCHED',0,'PROTOCOL: FULL (adversarial-searched 2026-05-11 session_2026-05-10f using native aliases 闪光火灾报警器/光报警器/视觉报警)

STANDARD: GB 50116-2013《火灾自动报警系统设计规范》 (Code for Design of Automatic Fire Alarm System) — mandatory national standard issued by MOHURD via 公安部沈阳消防研究所, effective 2014-05-01. Replaced GB 50116-98.

The standard has 24 mandatory provisions (强制性条文). It covers visual alarm devices (光报警器/视觉报警装置) primarily as supplementary devices for hearing-impaired notification, similar to JA approach.

ADVERSARIAL FINDING: GB 50116-2013 does NOT specify flash frequency limits for photosensitive epilepsy prevention. ZH-language search found no Chinese research on the strobe-seizure interaction or on photosensitive epilepsy in fire alarm context.

GAP: Major Chinese standard exists but addresses visual fire alarms as accessibility devices for hearing impairment, not as safety hazards for epilepsy. This is a regulatory gap relative to NFPA 72''s biological-safety framing.','2026-05-09 05:35','session_2026-05-09-search-coverage','2026-05-11 01:20','session_2026-05-10f-term-alias-expansion');
