INSERT OR IGNORE INTO spec_value_probes (probe_id,walk_id,slug,item_code,spec_value_origin,spec_unit,direction,population,claim_type,step_index,phase,step_value,step_value_unit,search_query,search_query_alt,passes_strict,ref_id,notes,created_at,created_by_session) VALUES ('PMP-A02-001-F','PMP-A02-001','school-environment-autism','A-02',0.85,'NRC','up','ALL','minimum',6,'final',0.935,'NRC',NULL,NULL,NULL,NULL,'V_empirical_ceiling=0.935 (NRC). Rounding to standard spec: NRC 0.90. gap_signed=+0.05. BPC spec (NRC ≥0.85) is BELOW ANSI S12.60 S5.3 minimum (NRC 0.90). BPC could raise threshold to NRC ≥0.90 to match standards evidence. ANSI/GBI 01-2019 also requires NRC 0.90 for healthcare/eldercare.','2026-05-10T20:39:54Z','session_2026-05-10e-slug3-adversarial');
